import{_ as e,o as a,c as o,a2 as t}from"./chunks/framework.DGp-bpT-.js";const k=JSON.parse('{"title":"Настройка интеграции со Slack","description":"","frontmatter":{},"headers":[],"relativePath":"guide/slack-setup.md","filePath":"guide/slack-setup.md","lastUpdated":1775054555000}'),i={name:"guide/slack-setup.md"};function l(n,s,r,c,p,d){return a(),o("div",null,[...s[0]||(s[0]=[t(`<h1 id="настроика-интеграции-со-slack" tabindex="-1">Настройка интеграции со Slack <a class="header-anchor" href="#настроика-интеграции-со-slack" aria-label="Permalink to &quot;Настройка интеграции со Slack&quot;">​</a></h1><p>Интеграция SREBot со Slack позволяет боту анализировать сообщения в каналах, искать в них алерты от Alertmanager и проводить их автоматический анализ с помощью ИИ.</p><p>Бот работает в режиме <strong>Socket Mode</strong>, что избавляет от необходимости настраивать публичные Webhooks и позволяет запускать бота даже за NAT или в закрытом контуре.</p><hr><h2 id="_1-регистрация-приложения-в-slack" tabindex="-1">1. Регистрация приложения в Slack <a class="header-anchor" href="#_1-регистрация-приложения-в-slack" aria-label="Permalink to &quot;1. Регистрация приложения в Slack&quot;">​</a></h2><ol><li>Перейдите на <a href="https://api.slack.com/apps" target="_blank" rel="noreferrer">Slack API: Your Apps</a>.</li><li>Нажмите <strong>Create New App</strong> -&gt; <strong>From scratch</strong>.</li><li>Назовите приложение (например, <code>SREBot</code>) и выберите свой Workspace.</li></ol><h2 id="_2-настроика-socket-mode" tabindex="-1">2. Настройка Socket Mode <a class="header-anchor" href="#_2-настроика-socket-mode" aria-label="Permalink to &quot;2. Настройка Socket Mode&quot;">​</a></h2><ol><li>В боковом меню выберите <strong>Settings -&gt; Socket Mode</strong>.</li><li>Включите переключатель <strong>Enable Socket Mode</strong>.</li><li>Slack предложит создать <strong>App-Level Token</strong>. <ul><li>Назовите его (например, <code>srebot-socket</code>).</li><li>Добавьте область (scope) <code>connections:write</code>.</li><li><strong>Сохраните этот токен</strong> – он начнется на <code>xapp-...</code>. В конфиге бота это <code>SLACK_APP_TOKEN</code>.</li></ul></li></ol><h2 id="_3-настроика-разрешении-scopes" tabindex="-1">3. Настройка разрешений (Scopes) <a class="header-anchor" href="#_3-настроика-разрешении-scopes" aria-label="Permalink to &quot;3. Настройка разрешений (Scopes)&quot;">​</a></h2><ol><li><p>Перейдите в <strong>Features -&gt; OAuth &amp; Permissions</strong>.</p></li><li><p>Прокрутите до раздела <strong>Scopes</strong> -&gt; <strong>Bot Token Scopes</strong>.</p></li><li><p>Добавйте следующие разрешения:</p><ul><li><code>channels:history</code> — чтобы бот видел сообщения в публичных каналах.</li><li><code>groups:history</code> — чтобы бот видел сообщения в приватных каналах.</li><li><code>chat:write</code> — чтобы бот мог отвечать в каналах.</li><li><code>app_mention:read</code> — чтобы бот реагировал на упоминания через <code>@</code>.</li></ul></li><li><p>Прокрутите вверх и нажмите <strong>Install to Workspace</strong>. После подтверждения вы получите <strong>Bot User OAuth Token</strong> (начинается на <code>xoxb-...</code>).</p><ul><li>Это <code>SLACK_BOT_TOKEN</code> в конфиге бота.</li></ul></li></ol><h2 id="_4-подписка-на-события-event-subscriptions" tabindex="-1">4. Подписка на события (Event Subscriptions) <a class="header-anchor" href="#_4-подписка-на-события-event-subscriptions" aria-label="Permalink to &quot;4. Подписка на события (Event Subscriptions)&quot;">​</a></h2><ol><li>Перейдите в <strong>Features -&gt; Event Subscriptions</strong>.</li><li>Включите <strong>Enable Events</strong>.</li><li>В разделе <strong>Subscribe to bot events</strong> добавьте: <ul><li><code>message.channels</code></li><li><code>message.groups</code> (если планируете использовать в приватных каналах)</li><li><code>app_mention</code></li></ul></li><li>Нажмите <strong>Save Changes</strong>.</li></ol><h2 id="_5-настроика-бота-env" tabindex="-1">5. Настройка бота (Env) <a class="header-anchor" href="#_5-настроика-бота-env" aria-label="Permalink to &quot;5. Настройка бота (Env)&quot;">​</a></h2><p>Добавьте полученные токены и ID канала в ваш файл <code>.env</code> или настройки Helm:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Токен бота (xoxb-...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">xoxb-your-bot-token</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Токен приложения (xapp-...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_APP_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">xapp-your-app-token</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ID канала, где бот должен слушать алерты</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C0123456789</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Чтобы узнать ID канала, нажмите на название канала в Slack -&gt; Settings -&gt; в самом низу будет &quot;Channel ID&quot;.</p></div><h2 id="_6-приглашение-бота-в-канал" tabindex="-1">6. Приглашение бота в канал <a class="header-anchor" href="#_6-приглашение-бота-в-канал" aria-label="Permalink to &quot;6. Приглашение бота в канал&quot;">​</a></h2><p>Бот не будет видеть сообщения, пока вы его не добавите в нужный канал:</p><ol><li>Зайдите в нужный канал в Slack.</li><li>Напишите <code>/invite @имя_вашего_бота</code>.</li></ol><hr><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><ul><li><strong>Автоматический анализ</strong>: Если бот добавлен в канал и имеет права <code>channels:history</code>, он автоматически подхватывает любые сообщения, похожие на алерты Alertmanager, и начинает их анализ.</li><li><strong>Упоминания</strong>: Вы можете отправить алерт и тегнуть бота (<code>@SREBot</code>), чтобы он принудительно проанализировал сообщение.</li><li><strong>Firing</strong>: Бот отправляет в канал сообщение-заглушку <code>🔍 Analyzing...</code>, затем редактирует его, заменяя на полноценный RCA-отчёт.</li><li><strong>Resolved</strong>: Бот отправляет уведомление <code>✅ Resolved: ...</code> только если он <strong>ранее анализировал</strong> этот алерт в текущем сеансе. Если resolved-сообщение пришло без предшествующего firing — оно тихо игнорируется.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>В целях безопасности бот автоматически маскирует Bearer-токены, API-ключи и пароли в выводе инструментов диагностики перед отправкой в LLM. Ваши credentials не попадут в историю анализа.</p></div>`,23)])])}const g=e(i,[["render",l]]);export{k as __pageData,g as default};
